MA5:=MA(CLOSE,5);
MA10:=MA(CLOSE,10);
MA20:=MA(CLOSE,20);
MA60:=MA(CLOSE,60);

{短期均线多头排列}
SHORT_BULL:=MA5>MA10 AND MA10>MA20;

{价格站上短期均线}
PRICE_ABOVE:=CLOSE>MA5 AND CLOSE>MA20;

{成交量放大 - 近5日均量大于前20日均量}
VOL_RATIO:=MA(VOL,5)/MA(VOL,20);
VOL_UP:=VOL_RATIO>1.0;

{综合选股条件}
ZZTC:=SHORT_BULL AND PRICE_ABOVE AND VOL_UP;

{输出}
ZZTC;

MA5:=MA(CLOSE,5);
MA10:=MA(CLOSE,10);
MA20:=MA(CLOSE,20);
MA60:=MA(CLOSE,60);
MA120:=MA(CLOSE,120);

{短期均线多头排列}
SHORT_BULL:=MA5>MA10 AND MA10>MA20;

{中期均线多头}
MEDIUM_BULL:=MA20>MA60;

{长期均线多头}
LONG_BULL:=MA60>MA120;

{价格位置}
ABOVE_MA5:=CLOSE>MA5;
ABOVE_MA20:=CLOSE>MA20;
ABOVE_MA60:=CLOSE>MA60;

{成交量}
VOL_RATIO:=MA(VOL,5)/MA(VOL,20);

{输出信号}
DRAWLINE(ABOVE_MA5,CLOSE,ABOVE_MA20,CLOSE,0);

{显示数值}
MA5;
MA10;
MA20;
MA60;
MA120;
VOL_RATIO;
